const text = $input.item.json.text.trim();
const match = text.match(/\b(?:T|TABLE)?\s*(\d+)\b/i);

if (!match) {
  return { 
    ...$input.item.json, 
    error: 'INVALID_TABLE', 
    error_msg: '❌ Invalid table number.\n\nPlease send a number between 1-' + (process.env.MAX_TABLES || '200')
  };
}

const tableNum = parseInt(match[1]);
const maxTables = parseInt(process.env.MAX_TABLES || '200');

if (tableNum < 1 || tableNum > maxTables) {
  return { 
    ...$input.item.json, 
    error: 'TABLE_OUT_RANGE', 
    error_msg: `❌ Table must be between 1-${maxTables}`
  };
}

const session = $input.item.json.session;
session.table = tableNum.toString();
session.table_set_at = Date.now();

return { 
  ...$input.item.json, 
  session: session,
  table_number: tableNum
};

