const items = $input.all().map(i => i.json);
const categories = {};

items.forEach(item => {
  if (!categories[item.category]) categories[item.category] = [];
  categories[item.category].push(item);
});

let menuText = `📋 *${process.env.RESTAURANT_NAME || 'Restaurant'} Menu*\n\n`;

Object.keys(categories).sort().forEach(cat => {
  const icon = cat === 'Beverages' ? '🥤' : cat === 'Food' ? '🍽️' : '🍰';
  menuText += `${icon} *${cat}*\n`;
  menuText += '━━━━━━━━━━\n';

  categories[cat].forEach(item => {
    menuText += `${item.code} - ${item.name}\n`;
    menuText += `    ₹${parseFloat(item.price).toFixed(2)}`;
    if (item.allergens) menuText += ` ⚠️ ${item.allergens}`;
    menuText += '\n';
  });
  menuText += '\n';
});

menuText += '\n💡 *How to Order:*\nSend item codes with quantity\nExample: B1 2 F3 1\n(means 2x B1 and 1x F3)';

return [{ 
  json: { 
    ...($input.first().json),
    menu_text: menuText,
    total_items: items.length
  } 
}];

const items = $input.all().map(i => i.json);

let text = '🔥 *Popular Items*\n━━━━━━━━━━\n\n';

items.forEach((item, idx) => {
