}];

const session = $input.item.json.session;

if (!session.cart || session.cart.length === 0) {
  return { 
    ...$input.item.json, 
    cart_empty: true, 
    cart_text: '🛒 *Your Cart is Empty*\n\nStart adding items!\n• View MENU\n• Check POPULAR items' 
  };
}

const lines = session.cart.map(item => {
  const subtotal = item.price * item.qty;
  return `${item.qty}x ${item.name}\n   ${item.code} - ₹${item.price.toFixed(2)} ea\n   Subtotal: ₹${subtotal.toFixed(2)}`;
});

const subtotal = session.cart.reduce((s, i) => s + (i.price * i.qty), 0);
const tax = subtotal * (parseFloat(process.env.TAX_RATE || '0.05'));
const total = subtotal + tax;

const text = `🛒 *Cart Summary*\nTable ${session.table}\n━━━━━━━━━━\n\n${lines.join('\n\n')}\n\n━━━━━━━━━━\nSubtotal: ₹${subtotal.toFixed(2)}\nTax (${(parseFloat(process.env.TAX_RATE || '0.05') * 100).toFixed(0)}%): ₹${tax.toFixed(2)}\n━━━━━━━━━━\n*Total: ₹${total.toFixed(2)}*\n\n💡 Commands:\n• CONFIRM - Place order\n• REMOVE <code> - Remove item\n• CLEAR - Empty cart\n• MENU - Add more`;

return { 
  ...$input.item.json, 
  cart_empty: false, 
  cart_text: text,
  cart_subtotal: subtotal,
  cart_tax: tax,
  cart_total: total,
  cart_count: session.cart.length
};

