const tokens = $input.item.json.text.split(/\s+/);
const items = [];

for (let i = 0; i < tokens.length; i++) {
  if (/^[A-Z]+\d+$/.test(tokens[i])) {
    let qty = 1;
    if (i + 1 < tokens.length && /^\d+$/.test(tokens[i + 1])) {
      qty = parseInt(tokens[i + 1]);
      i++;
    }
    if (qty < 1 || qty > 20) {
      return { 
        ...$input.item.json, 
        error: 'INVALID_QTY', 
        error_msg: '❌ Quantity must be 1-20' 
      };
    }
    items.push({ code: tokens[i], qty });
  }
}

if (!items.length) {
  return { 
    ...$input.item.json, 
    error: 'NO_ITEMS', 
    error_msg: '❌ No item codes found.\n\nFormat: B1 2\n(means 2x item B1)' 
  };
}

return { ...$input.item.json, parsed_items: items };

const menuItems = $input.all().slice(1).map(i => i.json);
const currentData = $input.first().json;
const parsedItems = currentData.parsed_items;
const session = currentData.session;

const validItems = [];
const invalidItems = [];

for (const item of parsedItems) {
  const menuItem = menuItems.find(m => m.code === item.code);
  if (menuItem && menuItem.is_available) {
    validItems.push({ 
      code: item.code, 
      name: menuItem.name, 
      price: parseFloat(menuItem.price), 
      qty: item.qty,
      category: menuItem.category
    });
  } else {
    invalidItems.push(item.code);
  }
}

if (invalidItems.length) {
  return { 
    ...currentData, 
    error: 'INVALID_CODES', 
    error_msg: `❌ Invalid or unavailable codes:\n${invalidItems.join(', ')}\n\nCheck MENU for valid codes` 
  };
}

for (const item of validItems) {
  const existing = session.cart.find(c => c.code === item.code);
  if (existing) {
    existing.qty += item.qty;
  } else {
    session.cart.push(item);
  }
}

return { 
  ...currentData, 
  session: session, 
  added_items: validItems,
  added_count: validItems.length
};

