const order = $input.all()[0]?.json;

if (!order || !order.order_id) {
  return [{
    json: {
      ...$input.first().json,
      status_text: '❌ No recent orders found.\n\nPlace your first order!\n• Type MENU to start'
    }
  }];
}

const statusEmoji = {
  'pending_payment': '💳',
  'paid': '✅',
  'preparing': '👨‍🍳',
  'ready': '🔔',
  'served': '✨',
  'cancelled': '❌'
};

const statusText = {
  'pending_payment': 'Awaiting Payment',
  'paid': 'Payment Received',
  'preparing': 'Being Prepared',
  'ready': 'Ready to Serve',
  'served': 'Served',
  'cancelled': 'Cancelled'
};

const emoji = statusEmoji[order.status] || '📋';
const status = statusText[order.status] || order.status;

const eta = order.estimated_time ? `\n⏱️ ETA: ${order.estimated_time} mins` : '';

const paymentNote = order.status === 'pending_payment' ? '\n\n⚠️ Please complete payment\nType: PAID after paying' : '';

const text = `${emoji} *Order Status*\n\n📋 Order: ${order.order_id}\n🪑 Table: ${order.table_number}\n💰 Total: ₹${parseFloat(order.total).toFixed(2)}\n\n━━━━━━━━━━\nStatus: ${status}${eta}\n━━━━━━━━━━${paymentNote}\n\n💡 We'll notify you when ready!`;

return [{
  json: {
    ...$input.first().json,
    status_text: text,
    current_status: order.status
  }
}];

const orders = $input.all().map(i => i.json);

if (!orders.length) {
  return [{
    json: {
      ...$input.first().json,
      history_text: '📜 *Order History*\n\nNo orders yet!\n\nStart ordering:\n• Type MENU\n• Type POPULAR'
    }
  }];
}

let text = '📜 *Order History*\n━━━━━━━━━━\n\n';

orders.forEach((order, idx) => {
  const date = new Date(order.created_at);
  const dateStr = date.toLocaleDateString('en-IN');
  const timeStr = date.toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit' });

  text += `${idx + 1}. Order ${order.order_id}\n`;
  text += `   📅 ${dateStr} ${timeStr}\n`;
  text += `   🪑 Table ${order.table_number}\n`;
  text += `   💰 ₹${parseFloat(order.total).toFixed(2)}\n`;
  text += `   Status: ${order.status}\n\n`;
});

text += '💡 Type STATUS for latest order';

return [{
  json: {
    ...$input.first().json,
    history_text: text
  }
}];

const text = $input.item.json.text;
const match = text.match(/^(?:REMOVE|DELETE)\s+([A-Z]+\d+)/i);

if (!match) {
  return { 
    ...$input.item.json, 
    error: 'INVALID_REMOVE', 
    error_msg: '❌ Invalid format.\n\nUse: REMOVE B1' 
  };
}

const code = match[1].toUpperCase();
const session = $input.item.json.session;
const itemIndex = session.cart.findIndex(i => i.code === code);

if (itemIndex === -1) {
  return { 
    ...$input.item.json, 
    error: 'ITEM_NOT_FOUND', 
    error_msg: `❌ ${code} not in cart.\n\nType CART to see items` 
  };
}

const removed = session.cart.splice(itemIndex, 1)[0];

return { 
  ...$input.item.json, 
  session: session,
  removed_item: removed
};
